import React from 'react';
import { useCurrency } from '../context/CurrencyContext';

export default function HomeScreen({ mainBalance, recentTransactions }) {
  const { formatAmount } = useCurrency();

  return (
    <div className="flex flex-col bg-white">
      {/* Main Balance */}
      <div className="px-6 py-6">
        <p className="text-sm font-bold text-gray-400 uppercase">Main Balance</p>
        <h2 className="text-3xl font-black text-gray-900">{formatAmount(mainBalance)}</h2>
      </div>

      {/* Recent Transactions */}
      <div className="px-6 mt-6">
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-sm font-black text-gray-900 uppercase">Recent Transactions</h3>
          <span className="text-gray-400 text-sm cursor-pointer">{'>'}</span>
        </div>
        <div className="space-y-4">
          {recentTransactions.map((tx, i) => (
            <div key={i} className="p-4 bg-gray-50 rounded-2xl border border-gray-100">
              <div className="flex justify-between">
                <p className="font-black text-gray-800">{tx.title}</p>
                <p className={`font-black ${tx.type === 'credit' ? 'text-emerald-600' : 'text-red-500'}`}>
                  {tx.type === 'credit' ? '+' : '-'}{formatAmount(tx.amount)}
                </p>
              </div>
              <p className="text-xs text-gray-400 mt-1">{tx.date}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
